    public List<EvidenceAddedEventResponse> getEvidenceAddedEvents(TransactionReceipt transactionReceipt) {
        List<Contract.EventValuesWithLog> valueList = extractEventParametersWithLog(EVIDENCEADDED_EVENT, transactionReceipt);
        ArrayList<EvidenceAddedEventResponse> responses = new ArrayList<EvidenceAddedEventResponse>(valueList.size());
        for (Contract.EventValuesWithLog eventValues : valueList) {
            EvidenceAddedEventResponse typedResponse = new EvidenceAddedEventResponse();
            typedResponse.log = eventValues.getLog();
            typedResponse.dataHash = (String) eventValues.getNonIndexedValues().get(0).getValue();
            typedResponse.bizType = (String) eventValues.getNonIndexedValues().get(1).getValue();
            typedResponse.bizId = (String) eventValues.getNonIndexedValues().get(2).getValue();
            typedResponse.uploader = (String) eventValues.getNonIndexedValues().get(3).getValue();
            typedResponse.timestamp = (BigInteger) eventValues.getNonIndexedValues().get(4).getValue();
            responses.add(typedResponse);
        }
        return responses;
    }

