            typedResponse.log = eventValues.getLog();
            typedResponse.verifier = (String) eventValues.getIndexedValues().get(0).getValue();
            typedResponse.dataHash = (String) eventValues.getNonIndexedValues().get(0).getValue();
            typedResponse.result = (Boolean) eventValues.getNonIndexedValues().get(1).getValue();
